def calculate_final_price(items, region, discount_code=None):
    total_subtotal = sum(item['price'] for item in items)

    if region == 'UK':
        vat_rate = 0.20
        return total_subtotal * (1 + vat_rate)
    elif region == 'EU':
        vat_rate = 0.21
        for item in items:
            if item['category'] == 'luxury':
                total_subtotal += item['price'] * 0.1
        return total_subtotal * (1 + vat_rate)
    elif region == 'US':
        if discount_code == 'SAVE10':
            return total_subtotal * 0.9
        return total_subtotal

def calculate_final_price(items, region, discount_code=None):
    # Total price before any VAT or luxury adjustments
    total_price = sum(item['price'] for item in items)

    # Apply luxury VAT (10%) to each luxury item individually, then sum
    luxury_adjusted_total = total_price
    for item in items:
        if item.get('is_luxury', False):
            luxury_adjusted_total += item['price'] * 0.10

    # Apply regional VAT (21% for EU, 0% otherwise) to the adjusted total
    if region == 'EU':
        final_price = luxury_adjusted_total * 1.21
    else:
        final_price = luxury_adjusted_total

    return final_price
